import mpvuePicker from '@/components/mpvue-picker/mpvuePicker.vue';
export default {
	components: {
		mpvuePicker
	},
	data() {
		return {
			isFirstLoad: true,
			TabCur: 0,
			searchTypeIndex: 0,
			searchTypeValue: "",
			searchTypeArr: [
				/* {
										label: '请假',
										value: 1
									}, */
				{
					label: '个人',
					value: "ReimbursementRequest"
				},
				{
					label: '分摊',
					value: "ExpendRequest"
				},
				/* {
					label: '付费',
					value: 4
				}, */
				{
					label: '借款',
					value: "BorrowRequest"
				}
			],
			themeColor: '#007AFF',
			scrollBarHeight: 0,
			mode: '',
			deepLength: 1,
			pickerValueDefault: [0],
			pageIndex: 0,
			dataList: [],
			modalName: null,
			isLoadMore: false,
			searchParams: [],
			searchValue: ""

		}
	},
	methods: {
		goDetail(item) {
			console.log(item);
			switch (item.BusinessType) {
				case "ReimbursementRequest":
					uni.navigateTo({
						url: '/pages/task/taskdetail/taskdetail?data=' + JSON.stringify(item)
					});
					break;
				case "ExpendRequest":
					uni.navigateTo({
						url: '/pages/task/taskdetail/taskcadetail?data=' + JSON.stringify(item)
					});
					break;
				case "BorrowRequest":
					uni.navigateTo({
						url: '/pages/task/taskdetail/taskrfdetail?data=' + JSON.stringify(item)
					});
					break;
				default:
					break;
			}
		},
		onCancel(e) {
			console.log(e)
		},
		onConfirm(e) {
			this.searchTypeIndex = e.index[0];
			this.searchTypeValue = this.searchTypeArr[this.searchTypeIndex].value;
		},
		showSinglePicker() {
			this.mode = 'selector'
			console.log(this.$refs);
			this.$refs.mpvuePicker.show()
		},
		tabSelect(e) {
			this.TabCur = e.currentTarget.dataset.id;
			this.scrollLeft = (e.currentTarget.dataset.id - 1) * 60
		},
		makeParams() {
			if (this.$mbservices.isEmpty(this.searchValue)) {
				this.searchParams = [];
				return false;
			}
			this.searchParams = [{
					FieldName: "BusinessType",
					Operation: "EQUAL",
					ConditionValue: this.searchTypeValue,
					Relationship: "AND"
				}
			];
			if(!this.$mbservices.isEmpty(this.searchValue))
			{
				var arr=[{
					FieldName: "DocEntry",
					Operation: "CONTAIN",
					ConditionValue: this.searchValue,
					Relationship: "OR"
				},
				{
					FieldName: "Remarks",
					Operation: "CONTAIN",
					ConditionValue: this.searchValue,
					Relationship: "OR"
				},
				{
					FieldName: "Amount",
					Operation: "CONTAIN",
					ConditionValue: this.searchValue,
					Relationship: "OR"
				}];
				arr.forEach(item=>{
					this.searchParams.push(item);
				})
			}
		},
		doSearch(e) {
			//this.dataList = [];
			this.makeParams();
			this.pageIndex = 0;
			this.getTaskList(this.searchParams);
		},
		loadMore() {
			if (this.searchValue != undefined && this.searchValue.length > 0) {
				this.makeParams();
			}
			this.isLoadMore = true;
			this.newShowGetTaskList(this.searchParams);
		},
		newShowGetTaskList: async function(params) {
			this.pageIndex = parseInt(this.pageIndex) + 1;
			var ajaxJSON = {
				pageIndex: this.pageIndex,
				rowsPerPage: '10',
				type: "Initialize",
				Parameter: {
					Sorts: [{
						FieldName: "DocEntry",
						type: "Descending"
					}],
					LoadChildren: 'NoLoad',
					Conditions: [{
							FieldName: "Canceled",
							Operation: "EQUAL",
							ConditionValue: 'N',
							Relationship: "AND"
						},
						{
							FieldName: "Closed",
							Operation: "EQUAL",
							ConditionValue: "N",
							Relationship: "AND"
						},
						{
							FieldName: "DocStatus",
							Operation: "EQUAL",
							ConditionValue: "O",
							Relationship: "AND"
						},
						{
							FieldName: "ApproveStatus",
							Operation: "EQUAL",
							ConditionValue: "P",
							Relationship: "AND"
						},
						{
							FieldName: "CreatorId",
							Operation: "EQUAL",
							ConditionValue: uni.getStorageSync('JSUserInfo').UserId,
							Relationship: "AND"
						}
					]
				}
			};
			if (params != undefined && params.length > 0) {
				params.forEach((item) => {
					ajaxJSON.Parameter.Conditions.push(item);
				});
			}
			var _this = this;
			this.$mbservices.Request(this.$webapi.getTaskList, 'POST', ajaxJSON, function(ret) {
				if (!ret.data.data) {
					_this.dataList = [];
					uni.showToast({
						title: '查无数据'
					});
					return false;
				}
				var _cacheList = [];
				ret.data.data.forEach((item) => {
					item.radchecked = false;
					if (item.ApproveStatus === 'Pending') {
						item.AApproveStatus = "待审核";
					}
					if (item.ApproveStatus === 'Approved') {
						item.AApproveStatus = "已批准";
					}
					if (item.ApproveStatus === 'Rejected') {
						item.AApproveStatus = "已拒绝";
					}
					if (item.BusinessType === "ReimbursementRequest") {
						item.BBusinessType = "个人报销"
					}
					if (item.BusinessType === "ExpendRequest") {
						item.BBusinessType = "分摊报销"
					}
					if (item.BusinessType === "BorrowRequest") {
						item.BBusinessType = "借款申请"
					}

					item.Amount = parseFloat(item.Amount).toFixed(2);
					_cacheList.push(item);
				});
				//_this.dataList = _cacheList;
				if (_this.isLoadMore) {
					if (_cacheList.length <= 0) {
						_this.pageIndex = parseInt(_this.pageIndex) - 1;
					}
					_cacheList.forEach(item => {
						_this.dataList.push(item);
					})
				} else {
					_this.dataList = _cacheList;
				}
			}, function(ret) {
				uni.showToast({
					title: ret.errMsg,
					icon: 'none',
					success: function() {
						setTimeout(function() {
							uni.navigateBack();
						}, 1000);
					}
				});
			});
		},
		getTaskList(params) {
			uni.showLoading({
				title: '拼命加载中...'
			});
			this.pageIndex = parseInt(this.pageIndex) + 1;
			var ajaxJSON = {
				pageIndex: this.pageIndex,
				rowsPerPage: '10',
				type: "Initialize",
				Parameter: { //
					Sorts: [{
						FieldName: "DocEntry",
						type: "Descending"
					}],
					LoadChildren: 'NoLoad',
					Conditions: [{
							FieldName: "Canceled",
							Operation: "EQUAL",
							ConditionValue: 'N',
							Relationship: "AND"
						},
						{
							FieldName: "Closed",
							Operation: "EQUAL",
							ConditionValue: "N",
							Relationship: "AND"
						},
						{
							FieldName: "DocStatus",
							Operation: "EQUAL",
							ConditionValue: "O",
							Relationship: "AND"
						},
						{
							FieldName: "ApproveStatus",
							Operation: "EQUAL",
							ConditionValue: "P",
							Relationship: "AND"
						},
						{
							FieldName: "CreatorId",
							Operation: "EQUAL",
							ConditionValue: uni.getStorageSync('JSUserInfo').UserId,
							Relationship: "AND"
						}
					]
				}
			};
			if (params != undefined && params.length > 0) {
				params.forEach((item) => {
					ajaxJSON.Parameter.Conditions.push(item);
				});
			}
			var _this = this;
			this.$mbservices.Request(this.$webapi.getTaskList, 'POST', ajaxJSON, function(ret) {
				if (!ret.data.data) {
					_this.dataList = [];
					uni.showToast({
						title: '查无数据'
					});
					return false;
				}
				//_this.dataList = [];
				var _cacheList = [];
				ret.data.data.forEach((item) => {
					item.radchecked = false;
					if (item.ApproveStatus === 'Pending') {
						item.AApproveStatus = "待审核";
					}
					if (item.ApproveStatus === 'Approved') {
						item.AApproveStatus = "已批准";
					}
					if (item.ApproveStatus === 'Rejected') {
						item.AApproveStatus = "已拒绝";
					}
					if (item.BusinessType === "ReimbursementRequest") {
						item.BBusinessType = "个人报销"
					}
					if (item.BusinessType === "ExpendRequest") {
						item.BBusinessType = "分摊报销"
					}
					if (item.BusinessType === "BorrowRequest") {
						item.BBusinessType = "借款申请"
					}

					item.Amount = parseFloat(item.Amount).toFixed(2);
					//_this.dataList.push(item);
					_cacheList.push(item);
				});
				_this.dataList = _cacheList;
				setTimeout(() => {
					uni.hideLoading();
				}, 1000);
			}, function(ret) {
				uni.showToast({
					title: ret.errMsg,
					icon: 'none',
					success: function() {
						setTimeout(function() {
							uni.navigateBack();
						}, 1000);
					}
				});
			});
		}
	},
	onShow() {
		/* if (!this.isFirstLoad) {
			this.pageIndex = parseInt(this.pageIndex) - 1;
			this.newShowGetTaskList();
		} */
		if (this.$mbservices.getIsRefresh()) {
			this.pageIndex = 0; // parseInt(this.pageIndex) - 1;
			this.$mbservices.setIsRefresh(false);
			this.newShowGetTaskList();
		}

		this.isFirstLoad = false;

	},
	onLoad() {

		const query = wx.createSelectorQuery();
		query.select("#_tabBar").boundingClientRect();
		query.selectViewport().scrollOffset();
		var _this = this;
		query.exec(function(res) {
			res[0].top; // #the-id节点的上边界坐标
			res[1].scrollTop; // 显示区域的竖直滚动位置
			_this.scrollBarHeight = uni.getSystemInfoSync().screenHeight - _this.CustomBar - res[0].height;
		});

		
		this.getTaskList();
	}
}
